arguments.command:
# Let's write a small C# program to read the binlog
mkdir -p /tmp/binlog-reader && cd /tmp/binlog-reader && cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

build.VisitAllChildren<Error>(error => {
    var project = "";
    var node = error.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    errors.Add((project, error.File ?? "", error.LineNumber, error.ColumnNumber, error.Code ?? "", error.Text ?? ""));
});

Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

// Group by project
var byProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in byProject) {
    Console.WriteLine($"=== Project: {group.Key} ===");
    foreach (var e in group) {
        Console.WriteLine($"  [{e.Code}] {e.File}({e.Line},{e.Col}): {e.Message}");
    }
    Console.WriteLine();
}
EOF

