cd /tmp/binlog-reader && cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check for failed projects (dependency failures)
var warnings = new List<(string Project, string Code, string Message)>();
build.VisitAllChildren<Warning>(w => {
    var project = "";
    var node = w.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    if (w.Code == "MSB3644" || w.Code == "NU1101" || w.Code == "MSB4181" || w.Text?.Contains("depend") == true || w.Text?.Contains("failed") == true)
        warnings.Add((project, w.Code ?? "", w.Text ?? ""));
});

Console.WriteLine("=== Relevant Warnings ===");
foreach (var w in warnings.Take(20)) {
    Console.WriteLine($"  [{w.Code}] {w.Project}: {w.Message}");
}

// Check all projects and their build results
Console.WriteLine("\n=== Project Build Results ===");
build.VisitAllChildren<Project>(p => {
    // Check if project succeeded
    var succeeded = p.FindChild<Folder>("Build")?.Children?.OfType<Message>()
        .Any(m => m.Text?.Contains("succeeded") == true) ?? false;
    if (!succeeded) {
        Console.WriteLine($"  Project: {p.Name} - may have failed");
    }
});

// Look for PackageReference items in the failing project
Console.WriteLine("\n=== NuGet Restore Messages ===");
build.VisitAllChildren<Message>(m => {
    if (m.Text?.Contains("Newtonsoft") == true || m.Text?.Contains("NU1101") == true || m.Text?.Contains("package") == true && m.Text?.Contains("Services") == true) {
        Console.WriteLine($"  {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
    }
});
EOF

