using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Deeper dive - look at Items with metadata
Console.WriteLine("=== Package/Project References with metadata ===");
build.VisitAllChildren<AddItem>(addItem => {
    if (addItem.Name == "PackageReference" || addItem.Name == "ProjectReference") {
        var project = "";
        var node = addItem.Parent;
        while (node != null) {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
        }
        foreach (var item in addItem.Children.OfType<Item>()) {
            var metadata = string.Join(", ", item.Children.OfType<Metadata>().Select(m => $"{m.Name}={m.Value}"));
            Console.WriteLine($"  {project} -> {addItem.Name}: {item.Text} [{metadata}]");
        }
    }
});

// Also check for the source file content
Console.WriteLine("\n=== Source Files in Services project ===");
build.VisitAllChildren<AddItem>(addItem => {
    if (addItem.Name == "Compile") {
        var project = "";
        var node = addItem.Parent;
        while (node != null) {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
        }
        if (project.Contains("Services") || project.Contains("Core") || project.Contains("Api"))
            foreach (var item in addItem.Children.OfType<Item>()) {
                Console.WriteLine($"  {project}: {item.Text}");
            }
    }
});
EOF

